#include <stdio.h>
#include <string.h>

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int ans1 = 0;
        char s[100000];
        scanf("%s", s);
        int n = strlen(s);
        for (int i = 1; i < n; i++) {
            if (s[i] != s[i - 1]) {
                ans1++;
                i++;
            }
        }
        printf("%d\n", ans1);
    }
    return 0;
}

code.Java:
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        sc.nextLine(); // Consume the newline character
        while (t-- > 0) {
            int ans1 = 0;
            String s = sc.nextLine();
            int n = s.length();
            for (int i = 1; i < n; i++) {
                if (s.charAt(i) != s.charAt(i - 1)) {
                    ans1++;
                    i++;
                }
            }
            System.out.println(ans1);
        }
    }
}
